import { useCallback, useMemo, useRef, useState } from "react";
import type {
  FileManagerSelectionChangeArgs,
  FsNode,
} from "../types";

interface UseSelectionArgs {
  controlledIds?: Set<string>;
  defaultIds?: Set<string>;
  onSelectedChange?: (args: FileManagerSelectionChangeArgs) => void;
  /** Used to drop ids that no longer reference live nodes. */
  index: Map<string, FsNode>;
}

export interface UseSelectionResult {
  selectedIds: ReadonlySet<string>;
  select: (idOrIds: string | string[]) => void;
  toggleSelection: (id: string) => void;
  clearSelection: () => void;
  selectAll: (visibleIds: string[]) => void;
  /** For Shift+click range select. Read in event handler context only. */
  getSelectionAnchorId: () => string | null;
  setSelectionAnchorId: (id: string | null) => void;
}

export function useSelection(args: UseSelectionArgs): UseSelectionResult {
  const { controlledIds, defaultIds, onSelectedChange, index } = args;

  const [internalIds, setInternalIds] = useState<Set<string>>(
    () => defaultIds ?? new Set(),
  );
  const anchorRef = useRef<string | null>(null);

  const selectedIds = controlledIds ?? internalIds;

  const setIds = useCallback(
    (next: Set<string>) => {
      if (controlledIds === undefined) setInternalIds(next);
      onSelectedChange?.({ ids: next });
    },
    [controlledIds, onSelectedChange],
  );

  const select = useCallback(
    (idOrIds: string | string[]) => {
      const ids = Array.isArray(idOrIds) ? idOrIds : [idOrIds];
      setIds(new Set(ids));
      if (ids.length > 0) anchorRef.current = ids[0];
    },
    [setIds],
  );

  const toggleSelection = useCallback(
    (id: string) => {
      const next = new Set(selectedIds);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      setIds(next);
      anchorRef.current = id;
    },
    [selectedIds, setIds],
  );

  const clearSelection = useCallback(() => {
    setIds(new Set());
    anchorRef.current = null;
  }, [setIds]);

  const selectAll = useCallback(
    (visibleIds: string[]) => {
      setIds(new Set(visibleIds));
    },
    [setIds],
  );

  const getSelectionAnchorId = useCallback(() => anchorRef.current, []);
  const setSelectionAnchorId = useCallback((id: string | null) => {
    anchorRef.current = id;
  }, []);

  // Sanitize: drop ids that no longer reference real nodes
  const sanitized = useMemo(() => {
    if (selectedIds.size === 0) return selectedIds;
    let dirty = false;
    const next = new Set<string>();
    for (const id of selectedIds) {
      if (index.has(id)) next.add(id);
      else dirty = true;
    }
    return dirty ? next : selectedIds;
  }, [selectedIds, index]);

  return {
    selectedIds: sanitized,
    select,
    toggleSelection,
    clearSelection,
    selectAll,
    getSelectionAnchorId,
    setSelectionAnchorId,
  };
}

"use client";

import { useCallback, useState } from "react";
import {
  EMPTY_CLIPBOARD,
  useFileClipboard,
  type FileClipboard,
} from "../../_shared/file-clipboard";
import type { FileManagerClipboardChangeArgs } from "../types";

interface UseClipboardArgs {
  /** Controlled clipboard (consumer manages state). */
  controlledClipboard?: FileClipboard;
  /** Initial value for uncontrolled mode. */
  defaultClipboard?: FileClipboard;
  onClipboardChange?: (args: FileManagerClipboardChangeArgs) => void;
}

export interface UseClipboardResult {
  clipboard: FileClipboard;
  cut: (ids: string[]) => void;
  copy: (ids: string[]) => void;
  clearClipboard: () => void;
  setClipboard: (next: FileClipboard) => void;
}

/**
 * Resolves clipboard state across three modes:
 *  1. Controlled (`controlledClipboard` prop given) — consumer drives.
 *  2. Provider (`<FileClipboardProvider>` up the tree) — synced across
 *     instances inside the provider.
 *  3. Internal — local `useState`.
 *
 * Mode is decided in priority order: controlled > provider > internal.
 */
export function useClipboard(args: UseClipboardArgs): UseClipboardResult {
  const { controlledClipboard, defaultClipboard, onClipboardChange } = args;

  const provider = useFileClipboard();
  const hasProvider = provider.__hasProvider;

  const [internalClipboard, setInternalClipboard] = useState<FileClipboard>(
    () => defaultClipboard ?? EMPTY_CLIPBOARD,
  );

  // Resolve current clipboard
  let clipboard: FileClipboard;
  if (controlledClipboard) {
    clipboard = controlledClipboard;
  } else if (hasProvider) {
    clipboard = provider.clipboard;
  } else {
    clipboard = internalClipboard;
  }

  const setClipboard = useCallback(
    (next: FileClipboard) => {
      if (!controlledClipboard) {
        if (hasProvider) provider.setClipboard(next);
        else setInternalClipboard(next);
      }
      onClipboardChange?.({ clipboard: next });
    },
    [controlledClipboard, hasProvider, provider, onClipboardChange],
  );

  const cut = useCallback(
    (ids: string[]) => {
      setClipboard({ kind: "cut", ids });
    },
    [setClipboard],
  );

  const copy = useCallback(
    (ids: string[]) => {
      setClipboard({ kind: "copy", ids });
    },
    [setClipboard],
  );

  const clearClipboard = useCallback(() => {
    setClipboard(EMPTY_CLIPBOARD);
  }, [setClipboard]);

  return {
    clipboard,
    cut,
    copy,
    clearClipboard,
    setClipboard,
  };
}

