export function useSortSearch(args: UseSortSearchArgs): UseSortSearchResult {
  const {
    controlledSort,
    defaultSort,
    onSortChange,
    controlledSearch,
    defaultSearch,
    onSearchChange,
    controlledViewMode,
    defaultViewMode,
    onViewModeChange,
    controlledIconSize,
    defaultIconSize,
    onIconSizeChange,
  } = args;

  const [internalSort, setInternalSort] = useState<FileManagerSortState>(
    defaultSort ?? DEFAULT_SORT,
  );
  const [internalSearch, setInternalSearch] = useState<string>(
    defaultSearch ?? "",
  );
  const [internalViewMode, setInternalViewMode] = useState<FileManagerViewMode>(
    defaultViewMode ?? "grid",
  );
  const [internalIconSize, setInternalIconSize] = useState<FileManagerIconSize>(
    defaultIconSize ?? "md",
  );

  const sort = controlledSort ?? internalSort;
  const searchQuery = controlledSearch ?? internalSearch;
  const viewMode = controlledViewMode ?? internalViewMode;
  const iconSize = controlledIconSize ?? internalIconSize;

  const setSort = useCallback(
    (next: FileManagerSortState) => {
      if (controlledSort === undefined) setInternalSort(next);
      onSortChange?.({ sort: next });
    },
    [controlledSort, onSortChange],
  );

  const setSearchQuery = useCallback(
    (next: string) => {
      if (controlledSearch === undefined) setInternalSearch(next);
      onSearchChange?.({ query: next });
    },
    [controlledSearch, onSearchChange],
  );

  const setViewMode = useCallback(
    (next: FileManagerViewMode) => {
      if (controlledViewMode === undefined) setInternalViewMode(next);
      onViewModeChange?.({ mode: next });
    },
    [controlledViewMode, onViewModeChange],
  );

  const setIconSize = useCallback(
    (next: FileManagerIconSize) => {
      if (controlledIconSize === undefined) setInternalIconSize(next);
      onIconSizeChange?.({ size: next });
    },
    [controlledIconSize, onIconSizeChange],
  );

  return {
    sort,
    searchQuery,
    viewMode,
    iconSize,
    setSort,
    setSearchQuery,
    setViewMode,
    setIconSize,
  };
}

"use client";

import { useMemo } from "react";
import type {
  FileClipboard,
  FileManagerItem,
  FileManagerSortState,
  FsNode,
} from "../types";
import { defaultSort, getChildrenOf } from "../lib/tree-utils";
import { getNodeExtension } from "../lib/icons";

interface UseVisibleItemsArgs {
  nodes: FsNode[];
  index: Map<string, FsNode>;
  currentFolderId: string | null;
  selectedIds: ReadonlySet<string>;
  focusedId: string | null;
  clipboard: FileClipboard;
  sort: FileManagerSortState;
  searchQuery: string;
  showHidden: boolean;
  isHidden?: (node: FsNode) => boolean;
  filterItems?: (node: FsNode, query: string) => boolean;
  sortItems?: (a: FsNode, b: FsNode, sort: FileManagerSortState) => number;
}

const defaultIsHidden = (node: FsNode) => node.name.startsWith(".");

const defaultFilter = (node: FsNode, query: string) =>
  node.name.toLowerCase().includes(query.toLowerCase());

function defaultSortBy(
  a: FsNode,
  b: FsNode,
  sort: FileManagerSortState,
): number {
  // folders always before files regardless of sort key (Mac Finder behavior)
  if (a.type !== b.type) return a.type === "folder" ? -1 : 1;

  let cmp = 0;
  switch (sort.key) {
    case "name":
      cmp = a.name.localeCompare(b.name, undefined, { sensitivity: "base" });
      break;
    case "modified": {
      const ta = a.modifiedAt ? new Date(a.modifiedAt).getTime() : 0;
      const tb = b.modifiedAt ? new Date(b.modifiedAt).getTime() : 0;
      cmp = ta - tb;
      break;
    }
    case "size":
      cmp = (a.size ?? 0) - (b.size ?? 0);
      break;
    case "type": {
      const ea = getNodeExtension(a);
      const eb = getNodeExtension(b);
      cmp = ea.localeCompare(eb, undefined, { sensitivity: "base" });
      if (cmp === 0) {
        cmp = a.name.localeCompare(b.name, undefined, { sensitivity: "base" });
      }
      break;
    }
  }
  return sort.order === "asc" ? cmp : -cmp;
}

export interface UseVisibleItemsResult {
  items: FileManagerItem[];
  /** Total size in bytes across visible items (folders contribute 0). */
  totalSize: number;
  /** Visible item count (post-filter, post-hidden). */
  visibleCount: number;
}

export function useVisibleItems(
  args: UseVisibleItemsArgs,
): UseVisibleItemsResult {
  const {
    nodes,
    index,
    currentFolderId,
    selectedIds,
    focusedId,
    clipboard,
    sort,
    searchQuery,
    showHidden,
    isHidden,
    filterItems,
    sortItems,
  } = args;

  return useMemo(() => {
    const children = getChildrenOf(currentFolderId, nodes, index) ?? [];
    const hiddenFn = isHidden ?? defaultIsHidden;
    const filterFn = filterItems ?? defaultFilter;
    const sorter = sortItems
      ? (a: FsNode, b: FsNode) => sortItems(a, b, sort)
      : (a: FsNode, b: FsNode) => defaultSortBy(a, b, sort);

    let filtered = showHidden
      ? [...children]
      : children.filter((n) => !hiddenFn(n));
    if (searchQuery.trim()) {
      filtered = filtered.filter((n) => filterFn(n, searchQuery));
    }
    filtered.sort(sorter);

    const cutSet = new Set(
      clipboard.kind === "cut" ? clipboard.ids : [],
    );

    const total = filtered.length;
    const totalSize = filtered.reduce(
      (sum, node) => sum + (node.type === "file" ? (node.size ?? 0) : 0),
      0,
    );
    const items: FileManagerItem[] = filtered.map((node, i) => ({
      node,
      selected: selectedIds.has(node.id),
      focused: focusedId === node.id,
      cut: cutSet.has(node.id),
      index: i,
      totalVisible: total,
    }));

    return { items, totalSize, visibleCount: total };
  }, [
    nodes,
    index,
    currentFolderId,
    selectedIds,
    focusedId,
    clipboard,
    sort,
    searchQuery,
    showHidden,
    isHidden,
    filterItems,
    sortItems,
  ]);
}

// fallback so the unused-import lint doesn't fire when defaultSort is
// referenced by tree-utils consumers expecting it to be available
void defaultSort;

"use client";

import { useCallback, useEffect, useRef, useState } from "react";
import type { FileManagerLoadChildrenArgs, FsNode } from "../types";

interface UseLazyLoadArgs {
  nodes: FsNode[];
  currentFolderId: string | null;
  index: Map<string, FsNode>;
  onLoadChildren?: (
    args: FileManagerLoadChildrenArgs,
  ) => Promise<FsNode[]>;
}

export interface UseLazyLoadResult {
  loadingChildren: boolean;
  loadError: string | null;
  retry: () => void;
}

/**
 * Auto-fires `onLoadChildren` when the current folder's `children` is
 * `undefined`. Per-folder loading + error state is keyed by folder id so
 * navigating between folders surfaces the right state without a clear effect.
 */
export function useLazyLoad(args: UseLazyLoadArgs): UseLazyLoadResult {
  const { currentFolderId, index, onLoadChildren } = args;
  const [loadingIds, setLoadingIds] = useState<Set<string>>(
    () => new Set(),
  );
  const [errorById, setErrorById] = useState<Map<string, string>>(
    () => new Map(),
  );
  const inFlightRef = useRef<Set<string>>(new Set());

  const triggerLoad = useCallback(
    async (folderId: string) => {
      if (!onLoadChildren) return;
      if (inFlightRef.current.has(folderId)) return;
      const node = index.get(folderId);
      if (!node || node.type !== "folder") return;
      inFlightRef.current.add(folderId);
      setLoadingIds((prev) => {
        const next = new Set(prev);
        next.add(folderId);
        return next;
      });
      setErrorById((prev) => {
        if (!prev.has(folderId)) return prev;
        const next = new Map(prev);
        next.delete(folderId);
        return next;
      });
      try {
        await onLoadChildren({ nodeId: folderId, node });
      } catch (err) {
        const msg = err instanceof Error ? err.message : "Failed to load";
        setErrorById((prev) => {
          const next = new Map(prev);
          next.set(folderId, msg);
          return next;
        });
      } finally {
        inFlightRef.current.delete(folderId);
        setLoadingIds((prev) => {
          if (!prev.has(folderId)) return prev;
          const next = new Set(prev);
          next.delete(folderId);
          return next;
        });
      }
    },
    [onLoadChildren, index],
  );

  useEffect(() => {
    if (!onLoadChildren || currentFolderId === null) return;
    const node = index.get(currentFolderId);
    if (!node || node.type !== "folder") return;
    if (node.children !== undefined) return;
    if (errorById.has(currentFolderId)) return;
    // Defer to the next microtask so the synchronous setLoadingIds inside
    // triggerLoad doesn't violate react-hooks/set-state-in-effect (kickoff
    // for async data fetch — sanctioned pattern).
    queueMicrotask(() => {
      void triggerLoad(currentFolderId);
    });
  }, [currentFolderId, index, onLoadChildren, triggerLoad, errorById]);

  const retry = useCallback(() => {
    if (currentFolderId === null) return;
    setErrorById((prev) => {
      if (!prev.has(currentFolderId)) return prev;
      const next = new Map(prev);
      next.delete(currentFolderId);
      return next;
    });
    void triggerLoad(currentFolderId);
  }, [currentFolderId, triggerLoad]);

  const loadingChildren =
    currentFolderId !== null && loadingIds.has(currentFolderId);
  const loadError =
    currentFolderId !== null
      ? (errorById.get(currentFolderId) ?? null)
      : null;

  return { loadingChildren, loadError, retry };
}

"use client";

import { useCallback, useRef, useState } from "react";
import type { PointerEvent as ReactPointerEvent } from "react";
import { getItemRects, rectanglesIntersect, type Rect } from "../lib/intersect";

interface UseMarqueeArgs {
  enabled: boolean;
  /** Apply the marquee's current selection. `additive` = shift held (add to existing). */
  applySelection: (ids: string[], additive: boolean) => void;
  /** Snapshot the current selection at marquee-start so additive mode can restore + extend. */
  snapshotSelection: () => Set<string>;
  /** Container element used for both rect query + scrolling. */
  containerRef: React.RefObject<HTMLDivElement | null>;
}

export interface MarqueeRect {
  left: number;
  top: number;
  width: number;
  height: number;
}

export interface UseMarqueeResult {
  rect: MarqueeRect | null;
  active: boolean;
  /** Bind to the content pane's pointer-down — only fires when pointer-down lands on whitespace. */
  onPointerDown: (e: ReactPointerEvent<HTMLDivElement>) => void;
}

export function useMarquee(args: UseMarqueeArgs): UseMarqueeResult {
  const { enabled, applySelection, snapshotSelection, containerRef } = args;

  const [rect, setRect] = useState<MarqueeRect | null>(null);
  const [active, setActive] = useState(false);
  const startRef = useRef<{
    x: number;
    y: number;
    additive: boolean;
    snapshot: Set<string>;
  } | null>(null);

  // Stable refs to handlers so cleanup matches the registered listener.
  const moveHandlerRef = useRef<((e: PointerEvent) => void) | null>(null);
  const upHandlerRef = useRef<((e: PointerEvent) => void) | null>(null);

  const onPointerDown = useCallback(
    (e: ReactPointerEvent<HTMLDivElement>) => {
      if (!enabled) return;
      if (e.button !== 0) return;
      const additive = e.shiftKey;
      const initialSelection = additive
        ? snapshotSelection()
        : new Set<string>();
      startRef.current = {
        x: e.clientX,
        y: e.clientY,
        additive,
        snapshot: initialSelection,
      };
      setActive(true);

      const handleMove = (moveEvent: PointerEvent) => {
        const start = startRef.current;
        const container = containerRef.current;
        if (!start || !container) return;
        const containerRect = container.getBoundingClientRect();
        const left = Math.min(start.x, moveEvent.clientX);
        const top = Math.min(start.y, moveEvent.clientY);
        const right = Math.max(start.x, moveEvent.clientX);
        const bottom = Math.max(start.y, moveEvent.clientY);
        setRect({
          left: left - containerRect.left,
          top: top - containerRect.top + container.scrollTop,
          width: right - left,
          height: bottom - top,
        });
        const marqueeRect: Rect = { left, top, right, bottom };
        const itemRects = getItemRects(container);
        const hit = new Set<string>();
        for (const [id, ir] of itemRects) {
          if (rectanglesIntersect(marqueeRect, ir)) hit.add(id);
        }
        const ids = Array.from(hit);
        applySelection(
          start.additive
            ? Array.from(new Set([...start.snapshot, ...ids]))
            : ids,
          start.additive,
        );
      };

      const handleUp = () => {
        startRef.current = null;
        setActive(false);
        setRect(null);
        if (moveHandlerRef.current)
          window.removeEventListener("pointermove", moveHandlerRef.current);
        if (upHandlerRef.current) {
          window.removeEventListener("pointerup", upHandlerRef.current);
          window.removeEventListener("pointercancel", upHandlerRef.current);
        }
        moveHandlerRef.current = null;
        upHandlerRef.current = null;
      };

      moveHandlerRef.current = handleMove;
      upHandlerRef.current = handleUp;
      window.addEventListener("pointermove", handleMove);
      window.addEventListener("pointerup", handleUp);
      window.addEventListener("pointercancel", handleUp);
    },
    [enabled, snapshotSelection, applySelection, containerRef],
  );

  return { rect, active, onPointerDown };
}

"use client";

import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import type { DragEvent } from "react";
import type {
  FileManagerDropPosition,
  FileManagerExternalDropArgs,
  FileManagerItem,
  FileManagerMoveArgs,
  FsNode,
} from "../types";
import { isLegalDrop } from "../lib/validation";
import { indexNodes } from "../lib/tree-utils";

/** Same MIME marker file-tree uses — enables cross-component drops. */
const INTERNAL_MIME = "application/x-ilinxa-file-tree";

const AUTO_SCROLL_EDGE_PX = 24;
const AUTO_SCROLL_PX_PER_FRAME = 4;

export interface DragOverState {
  /** Item id currently being hovered as a drop target. `null` = container. */
  itemId: string | null;
  valid: boolean;
}

interface UseDragArgs {
  nodes: FsNode[];
  currentFolderId: string | null;
  enableInternalDrag: boolean;
  enableExternalDrop: boolean;
  selectedIds: ReadonlySet<string>;
  onMove?: (args: FileManagerMoveArgs) => void;
  onExternalDrop?: (args: FileManagerExternalDropArgs) => void;
  /** Replace selection with a single id (used at drag-start when source isn't selected). */
  selectIds: (idOrIds: string | string[]) => void;
}

export interface UseDragResult {
  dragOver: DragOverState | null;
  isExternalDragging: boolean;
  isInternalDragging: boolean;
  // Item-level handlers
  onItemDragStart: (e: DragEvent, item: FileManagerItem) => void;
  onItemDragOver: (e: DragEvent, item: FileManagerItem) => void;
  onItemDragLeave: (e: DragEvent, item: FileManagerItem) => void;
  onItemDrop: (e: DragEvent, item: FileManagerItem) => void;
  onItemDragEnd: (e: DragEvent, item: FileManagerItem) => void;
  // Container handlers (scroll area)
  onContainerDragEnter: (e: DragEvent) => void;
  onContainerDragOver: (e: DragEvent) => void;
  onContainerDragLeave: (e: DragEvent) => void;
  onContainerDrop: (e: DragEvent) => void;
}

export function useDrag(args: UseDragArgs): UseDragResult {
  const {
    nodes,
    currentFolderId,
    enableInternalDrag,
    enableExternalDrop,
    selectedIds,
    onMove,
    onExternalDrop,
    selectIds,
  } = args;

  const [dragOver, setDragOver] = useState<DragOverState | null>(null);
  const [isExternalDragging, setIsExternalDragging] = useState(false);
  const [isInternalDragging, setIsInternalDragging] = useState(false);
  const isInternalDraggingRef = useRef(false);
  const externalEnterCountRef = useRef(0);
  const dragSourceIdsRef = useRef<string[]>([]);
  const autoScrollRef = useRef<{
    container: HTMLElement | null;
    direction: number;
    raf: number | null;
  }>({ container: null, direction: 0, raf: null });

  const nodeIndex = useMemo(() => indexNodes(nodes), [nodes]);

  const stopAutoScroll = useCallback(() => {
    const ref = autoScrollRef.current;
    if (ref.raf !== null) {
      cancelAnimationFrame(ref.raf);
      ref.raf = null;
    }
    ref.direction = 0;
    ref.container = null;
  }, []);

  const startAutoScroll = useCallback(
    (container: HTMLElement | null, clientY: number) => {
      if (!container) return;
      const rect = container.getBoundingClientRect();
      let dir = 0;
      if (clientY - rect.top < AUTO_SCROLL_EDGE_PX) dir = -1;
      else if (rect.bottom - clientY < AUTO_SCROLL_EDGE_PX) dir = 1;
      const ref = autoScrollRef.current;
      ref.container = container;
      if (dir !== ref.direction) {
        ref.direction = dir;
        if (ref.raf !== null) {
          cancelAnimationFrame(ref.raf);
          ref.raf = null;
        }
        if (dir !== 0) {
          const tick = () => {
            const r = autoScrollRef.current;
            if (r.container && r.direction !== 0) {
              r.container.scrollTop +=
                r.direction * AUTO_SCROLL_PX_PER_FRAME;
              r.raf = requestAnimationFrame(tick);
            } else {
              r.raf = null;
            }
          };
          ref.raf = requestAnimationFrame(tick);
        }
      }
    },
    [],
  );

  useEffect(() => {
    return () => stopAutoScroll();
  }, [stopAutoScroll]);

  const onItemDragStart = useCallback(
    (e: DragEvent, item: FileManagerItem) => {
      if (!enableInternalDrag) return;
      let ids: string[];
      if (selectedIds.has(item.node.id) && selectedIds.size > 1) {
        ids = Array.from(selectedIds);
      } else {
        ids = [item.node.id];
        selectIds(item.node.id);
      }
      dragSourceIdsRef.current = ids;
      isInternalDraggingRef.current = true;
      setIsInternalDragging(true);
      try {
        e.dataTransfer.effectAllowed = "move";
        e.dataTransfer.setData(INTERNAL_MIME, "1");
      } catch {
        /* ignored */
      }
    },
    [enableInternalDrag, selectedIds, selectIds],
  );

  const onItemDragEnd = useCallback(() => {
    isInternalDraggingRef.current = false;
    setIsInternalDragging(false);
    dragSourceIdsRef.current = [];
    setDragOver(null);
    stopAutoScroll();
  }, [stopAutoScroll]);

  const onItemDragOver = useCallback(
    (e: DragEvent, item: FileManagerItem) => {
      if (!isInternalDraggingRef.current) return;
      e.preventDefault();
      // Drops are only legal on folders
      const validTarget = item.node.type === "folder";
      const position: FileManagerDropPosition = "inside";
      const valid =
        validTarget &&
        isLegalDrop({
          srcIds: dragSourceIdsRef.current,
          targetId: item.node.id,
          position,
          index: nodeIndex,
        });
      e.dataTransfer.dropEffect = valid ? "move" : "none";
      setDragOver({ itemId: item.node.id, valid });
      const scroller = (e.currentTarget as HTMLElement).closest(
        "[data-file-manager-scroller]",
      ) as HTMLElement | null;
      startAutoScroll(scroller, e.clientY);
    },
    [nodeIndex, startAutoScroll],
  );

  const onItemDragLeave = useCallback(
    (_e: DragEvent, item: FileManagerItem) => {
      setDragOver((prev) =>
        prev?.itemId === item.node.id ? null : prev,
      );
    },
    [],
  );

  const onItemDrop = useCallback(
    (e: DragEvent, item: FileManagerItem) => {
      if (!isInternalDraggingRef.current) return;
      e.preventDefault();
      const validTarget = item.node.type === "folder";
      const ids = dragSourceIdsRef.current;
      if (!validTarget) {
        // rejected
        setDragOver(null);
        stopAutoScroll();
        isInternalDraggingRef.current = false;
        setIsInternalDragging(false);
        dragSourceIdsRef.current = [];
        return;
      }
      const valid = isLegalDrop({
        srcIds: ids,
        targetId: item.node.id,
        position: "inside",
        index: nodeIndex,
      });
      if (valid && onMove) {
        onMove({ ids, targetId: item.node.id, position: "inside" });
      }
      setDragOver(null);
      stopAutoScroll();
      isInternalDraggingRef.current = false;
      setIsInternalDragging(false);
      dragSourceIdsRef.current = [];
    },
    [nodeIndex, onMove, stopAutoScroll],
  );

  // Container-level (whitespace) handlers
  const hasFiles = (e: DragEvent) =>
    Array.from(e.dataTransfer.types).includes("Files");

  const onContainerDragEnter = useCallback(
    (e: DragEvent) => {
      if (!enableExternalDrop) return;
      if (!hasFiles(e)) return;
      externalEnterCountRef.current += 1;
      setIsExternalDragging(true);
    },
    [enableExternalDrop],
  );

  const onContainerDragOver = useCallback(
    (e: DragEvent) => {
      if (enableExternalDrop && hasFiles(e)) {
        e.preventDefault();
        e.dataTransfer.dropEffect = "copy";
      } else if (isInternalDraggingRef.current) {
        e.preventDefault();
        e.dataTransfer.dropEffect = "none"; // dropping on whitespace internal = no-op
        setDragOver(null);
        // auto-scroll if near edges
        const scroller = e.currentTarget as HTMLElement;
        startAutoScroll(scroller, e.clientY);
      }
    },
    [enableExternalDrop, startAutoScroll],
  );

  const onContainerDragLeave = useCallback(
    (e: DragEvent) => {
      if (!enableExternalDrop) return;
      if (!hasFiles(e)) return;
      externalEnterCountRef.current = Math.max(
        0,
        externalEnterCountRef.current - 1,
      );
      if (externalEnterCountRef.current === 0) {
        setIsExternalDragging(false);
      }
    },
    [enableExternalDrop],
  );

  const onContainerDrop = useCallback(
    (e: DragEvent) => {
      if (enableExternalDrop && hasFiles(e)) {
        e.preventDefault();
        externalEnterCountRef.current = 0;
        setIsExternalDragging(false);
        const target = e.target as HTMLElement | null;
        const itemEl = target?.closest("[data-item-id]") as
          | HTMLElement
          | null;
        const itemId = itemEl?.getAttribute("data-item-id") ?? null;
        let targetFolderId: string | null = currentFolderId;
        if (itemId) {
          const node = nodeIndex.get(itemId);
          if (node?.type === "folder") targetFolderId = itemId;
        }
        const files = Array.from(e.dataTransfer.files ?? []);
        if (files.length > 0) {
          onExternalDrop?.({ files, targetFolderId });
        }
        return;
      }
      // Internal drag onto whitespace = no-op
      if (isInternalDraggingRef.current) {
        e.preventDefault();
        isInternalDraggingRef.current = false;
        setIsInternalDragging(false);
        dragSourceIdsRef.current = [];
        setDragOver(null);
        stopAutoScroll();
      }
    },
    [
      enableExternalDrop,
      currentFolderId,
      nodeIndex,
      onExternalDrop,
      stopAutoScroll,
    ],
  );

  return {
    dragOver,
    isExternalDragging,
    isInternalDragging,
    onItemDragStart,
    onItemDragOver,
    onItemDragLeave,
    onItemDrop,
    onItemDragEnd,
    onContainerDragEnter,
    onContainerDragOver,
    onContainerDragLeave,
    onContainerDrop,
  };
}

"use client";

import { useCallback, useRef } from "react";
import type { KeyboardEvent } from "react";
import type {
  FileManagerActions,
  FileManagerItem,
  FileManagerOpenArgs,
  FileManagerViewMode,
} from "../types";

interface UseKeyboardArgs {
  items: FileManagerItem[];
  focusedId: string | null;
  renamingId: string | null;
  selectedIds: ReadonlySet<string>;
  viewMode: FileManagerViewMode;
  /** Live ref to the current column count in grid mode (computed by content-pane). */
  columnsRef: React.MutableRefObject<number>;
  actions: FileManagerActions;
  onOpen?: (args: FileManagerOpenArgs) => void;
}

const SUPPRESS_TAGS = ["INPUT", "TEXTAREA", "SELECT"];

export interface UseKeyboardResult {
  onKeyDown: (e: KeyboardEvent<HTMLDivElement>) => void;
}

export function useKeyboard(args: UseKeyboardArgs): UseKeyboardResult {
  const {
    items,
    focusedId,
    renamingId,
    selectedIds,
    viewMode,
    columnsRef,
    actions,
    onOpen,
  } = args;

  // Type-ahead state
  const typeAheadRef = useRef<{ prefix: string; timer: number | null }>({
    prefix: "",
    timer: null,
  });

  const onKeyDown = useCallback(
    (e: KeyboardEvent<HTMLDivElement>) => {
      const target = e.target as HTMLElement | null;
      if (target && SUPPRESS_TAGS.includes(target.tagName)) return;
      if (renamingId) return;

      const isMod = e.metaKey || e.ctrlKey;
      const idx = items.findIndex((item) => item.node.id === focusedId);
      const noFocus = idx === -1;
      const cols = Math.max(1, columnsRef.current || 1);

      switch (e.key) {
        case "ArrowDown": {
          e.preventDefault();
          if (noFocus) {
            if (items[0]) actions.focusNode(items[0].node.id);
            return;
          }
          const step = viewMode === "grid" ? cols : 1;
          const next = Math.min(items.length - 1, idx + step);
          if (items[next]) actions.focusNode(items[next].node.id);
          return;
        }
        case "ArrowUp": {
          e.preventDefault();
          if (noFocus) {
            if (items[0]) actions.focusNode(items[0].node.id);
            return;
          }
          const step = viewMode === "grid" ? cols : 1;
          const next = Math.max(0, idx - step);
          if (items[next]) actions.focusNode(items[next].node.id);
          return;
        }
        case "ArrowRight": {
          if (viewMode !== "grid") return;
          e.preventDefault();
          if (noFocus) {
            if (items[0]) actions.focusNode(items[0].node.id);
            return;
          }
          const next = Math.min(items.length - 1, idx + 1);
          if (items[next]) actions.focusNode(items[next].node.id);
          return;
        }
        case "ArrowLeft": {
          if (viewMode !== "grid") return;
          e.preventDefault();
          if (noFocus) {
            if (items[0]) actions.focusNode(items[0].node.id);
            return;
          }
          const next = Math.max(0, idx - 1);
          if (items[next]) actions.focusNode(items[next].node.id);
          return;
        }
        case "Home": {
          e.preventDefault();
          if (items[0]) actions.focusNode(items[0].node.id);
          return;
        }
        case "End": {
          e.preventDefault();
          const last = items[items.length - 1];
          if (last) actions.focusNode(last.node.id);
          return;
        }
        case "Enter": {
          if (noFocus) return;
          e.preventDefault();
          const item = items[idx];
          if (item.node.type === "folder") {
            actions.navigateTo(item.node.id);
          } else {
            onOpen?.({ node: item.node });
          }
          return;
        }
        case " ":
        case "Spacebar": {
          if (noFocus) return;
          e.preventDefault();
          actions.toggleSelection(items[idx].node.id);
          return;
        }
        case "F2": {
          if (noFocus) return;
          e.preventDefault();
          actions.startRename(items[idx].node.id);
          return;
        }
        case "Delete": {
          if (selectedIds.size === 0) return;
          e.preventDefault();
          actions.triggerDelete(Array.from(selectedIds));
          return;
        }
        case "Backspace": {
          if (selectedIds.size > 0) {
            e.preventDefault();
            actions.triggerDelete(Array.from(selectedIds));
          } else {
            e.preventDefault();
            actions.navigateUp();
          }
          return;
        }
        case "Escape": {
          if (selectedIds.size > 0) {
            e.preventDefault();
            actions.clearSelection();
          }
          return;
        }
        case "a":
        case "A": {
          if (!isMod) break;
          e.preventDefault();
          actions.selectAll();
          return;
        }
        case "x":
        case "X": {
          if (!isMod) break;
          if (selectedIds.size === 0) return;
          e.preventDefault();
          actions.cut(Array.from(selectedIds));
          return;
        }
        case "c":
        case "C": {
          if (!isMod) break;
          if (selectedIds.size === 0) return;
          e.preventDefault();
          actions.copy(Array.from(selectedIds));
          return;
        }
        case "v":
        case "V": {
          if (!isMod) break;
          e.preventDefault();
          actions.paste();
          return;
        }
        case "[": {
          if (!isMod) break;
          e.preventDefault();
          actions.navigateBack();
          return;
        }
        case "]": {
          if (!isMod) break;
          e.preventDefault();
          actions.navigateForward();
          return;
        }
      }

      // Type-ahead: a single printable character (no modifier)
      if (!isMod && e.key.length === 1 && /\S/.test(e.key)) {
        const ta = typeAheadRef.current;
        ta.prefix += e.key.toLowerCase();
        if (ta.timer !== null) window.clearTimeout(ta.timer);
        ta.timer = window.setTimeout(() => {
          ta.prefix = "";
          ta.timer = null;
        }, 800);
        const match = items.find((item) =>
          item.node.name.toLowerCase().startsWith(ta.prefix),
        );
        if (match) {
          e.preventDefault();
          actions.focusNode(match.node.id);
        }
      }
    },
    [
      items,
      focusedId,
      renamingId,
      selectedIds,
      viewMode,
      columnsRef,
      actions,
      onOpen,
    ],
  );

  return { onKeyDown };
}

import type { FsNode } from "../types";

/** Flat-index a hierarchical array by id. */
export function indexNodes(nodes: FsNode[]): Map<string, FsNode> {
  const map = new Map<string, FsNode>();
  const walk = (list: FsNode[]) => {
    for (const node of list) {
      if (map.has(node.id)) continue;
      map.set(node.id, node);
      if (node.children) walk(node.children);
    }
  };
  walk(nodes);
  return map;
}

export function findNode(
  id: string,
  nodes: FsNode[],
): FsNode | undefined {
  for (const node of nodes) {
    if (node.id === id) return node;
    if (node.children) {
      const hit = findNode(id, node.children);
      if (hit) return hit;
    }
  }
  return undefined;
}

export function getParentChain(
  nodeId: string,
  index: Map<string, FsNode>,
): FsNode[] {
  const chain: FsNode[] = [];
  let current = index.get(nodeId);
  while (current?.parentId) {
    const parent = index.get(current.parentId);
    if (!parent) break;
    chain.unshift(parent);
    current = parent;
  }
  return chain;
}

export function getDescendantIds(
  nodeId: string,
  index: Map<string, FsNode>,
): Set<string> {
  const out = new Set<string>();
  const node = index.get(nodeId);
  if (!node?.children) return out;
  const walk = (list: FsNode[]) => {
    for (const child of list) {
      if (out.has(child.id)) continue;
      out.add(child.id);
      if (child.children) walk(child.children);
    }
  };
  walk(node.children);
  return out;
}

/** Default sort: folders first, then case-insensitive locale alpha by name. */
export function defaultSort(a: FsNode, b: FsNode): number {
  if (a.type !== b.type) return a.type === "folder" ? -1 : 1;
  return a.name.localeCompare(b.name, undefined, { sensitivity: "base" });
}

/** Children of a given folder id; null = root-level nodes. */
export function getChildrenOf(
  folderId: string | null,
  nodes: FsNode[],
  index: Map<string, FsNode>,
): FsNode[] | undefined {
  if (folderId === null) return nodes;
  const folder = index.get(folderId);
  if (!folder) return undefined;
  if (folder.type !== "folder") return undefined;
  return folder.children;
}

function replaceChildren(
  nodes: FsNode[],
  parentId: string,
  next: FsNode[],
): FsNode[] {
  let changed = false;
  const out = nodes.map((node) => {
    if (node.id === parentId) {
      changed = true;
      return { ...node, children: next };
    }
    if (node.children) {
      const replaced = replaceChildren(node.children, parentId, next);
      if (replaced !== node.children) {
        changed = true;
        return { ...node, children: replaced };
      }
    }
    return node;
  });
  return changed ? out : nodes;
}

/** Public consumer helper for splicing lazy-loaded children into the tree. */
export function mergeLoadedChildren(
  nodes: FsNode[],
  parentId: string,
  children: FsNode[],
): FsNode[] {
  return replaceChildren(nodes, parentId, children);
}

export function countAllNodes(nodes: FsNode[]): number {
  let total = 0;
  const walk = (list: FsNode[]) => {
    for (const node of list) {
      total += 1;
      if (node.children) walk(node.children);
    }
  };
  walk(nodes);
  return total;
}

import type { FsNode, FileManagerDropPosition } from "../types";

export function isSelfDrop(
  srcIds: string[],
  targetId: string | null,
): boolean {
  if (!targetId) return false;
  return srcIds.includes(targetId);
}

export function isCycle(
  srcIds: string[],
  targetId: string | null,
  index: Map<string, FsNode>,
): boolean {
  if (!targetId) return false;
  const set = new Set(srcIds);
  let current: FsNode | undefined = index.get(targetId);
  while (current) {
    if (set.has(current.id)) return true;
    const parentId = current.parentId;
    if (!parentId) break;
    current = index.get(parentId);
  }
  return false;
}

export interface IsLegalDropArgs {
  srcIds: string[];
  targetId: string | null;
  position: FileManagerDropPosition;
  index: Map<string, FsNode>;
}

export function isLegalDrop({
  srcIds,
  targetId,
  position,
  index,
}: IsLegalDropArgs): boolean {
  if (srcIds.length === 0) return false;
  if (isSelfDrop(srcIds, targetId)) return false;
  if (position === "inside" && isCycle(srcIds, targetId, index)) return false;
  return true;
}

/** Soft-validate a node tree on mount. */
export function validateNodes(nodes: FsNode[]): string[] {
  const warnings: string[] = [];
  const ids = new Set<string>();
  const walk = (list: FsNode[], path: Set<string>) => {
    for (const node of list) {
      if (ids.has(node.id)) {
        warnings.push(`duplicate node id: "${node.id}"`);
        continue;
      }
      ids.add(node.id);
      if (path.has(node.id)) {
        warnings.push(`cycle detected at node: "${node.id}"`);
        continue;
      }
      if (node.children) {
        const next = new Set(path);
        next.add(node.id);
        walk(node.children, next);
      }
    }
  };
  walk(nodes, new Set());
  return warnings;
}

import type { FsNode } from "../types";
import { getParentChain } from "./tree-utils";

/**
 * Build the path from root → ... → currentFolder. Empty array when at root
 * (`currentFolderId === null`). Returns the chain of FsNodes.
 */
export function buildPath(
  currentFolderId: string | null,
  index: Map<string, FsNode>,
): FsNode[] {
  if (currentFolderId === null) return [];
  const current = index.get(currentFolderId);
  if (!current) return [];
  const chain = getParentChain(currentFolderId, index);
  return [...chain, current];
}

/**
 * Best-effort string-to-id resolution. Looks for a node whose name path
 * (from root) matches the typed segments. Returns the id of the matching
 * folder, or `null` if no match.
 *
 * Consumer typically provides their own resolver via `onPathTyped`; this
 * helper is for the simple case where path segments map directly to node
 * names.
 */
export function parsePath(
  path: string,
  nodes: FsNode[],
): string | null {
  const segments = path.split(/[/\\]/).filter(Boolean);
  if (segments.length === 0) return null;

  let current: FsNode[] | undefined = nodes;
  let lastMatchId: string | null = null;
  for (const segment of segments) {
    if (!current) return null;
    const match: FsNode | undefined = current.find(
      (n: FsNode) =>
        n.type === "folder" &&
        n.name.localeCompare(segment, undefined, { sensitivity: "base" }) ===
          0,
    );
    if (!match) return null;
    lastMatchId = match.id;
    current = match.children;
  }
  return lastMatchId;
}

export interface Rect {
  left: number;
  top: number;
  right: number;
  bottom: number;
}

/** AABB rectangle intersection. */
export function rectanglesIntersect(a: Rect, b: Rect): boolean {
  return !(
    a.right < b.left ||
    a.left > b.right ||
    a.bottom < b.top ||
    a.top > b.bottom
  );
}

/**
 * Collect bounding rects of every item currently rendered inside `scroller`,
 * keyed by `data-item-id`. Used by the marquee hook to determine which items
 * the rectangle currently covers.
 *
 * Rects are in viewport coordinates (`getBoundingClientRect`); callers
 * comparing against the marquee rectangle should use the same coordinate
 * space.
 */
export function getItemRects(
  scroller: HTMLElement | null,
): Map<string, Rect> {
  const out = new Map<string, Rect>();
  if (!scroller) return out;
  const items = scroller.querySelectorAll<HTMLElement>("[data-item-id]");
  for (const el of items) {
    const id = el.getAttribute("data-item-id");
    if (!id) continue;
    const rect = el.getBoundingClientRect();
    out.set(id, {
      left: rect.left,
      top: rect.top,
      right: rect.right,
      bottom: rect.bottom,
    });
  }
  return out;
}

/** Format bytes as a human-readable string ("4.2 MB", "812 KB", "32 B"). */
export function formatBytes(bytes: number): string {
  if (!Number.isFinite(bytes) || bytes < 0) return "—";
  if (bytes === 0) return "0 B";
  const units = ["B", "KB", "MB", "GB", "TB"];
  let value = bytes;
  let unit = 0;
  while (value >= 1024 && unit < units.length - 1) {
    value /= 1024;
    unit += 1;
  }
  const rounded = value < 10 ? value.toFixed(1) : Math.round(value).toString();
  return `${rounded} ${units[unit]}`;
}

const dateFormatter = new Intl.DateTimeFormat(undefined, {
  year: "numeric",
  month: "short",
  day: "numeric",
});

/** Format an ISO date string as "May 9, 2026". Returns the input if unparseable. */
export function formatDate(iso: string | undefined): string {
  if (!iso) return "—";
  const date = new Date(iso);
  if (Number.isNaN(date.getTime())) return iso;
  return dateFormatter.format(date);
}

/** Capitalize an extension for display in the list view's Type column. */
export function formatKind(ext: string, type: "file" | "folder"): string {
  if (type === "folder") return "Folder";
  if (!ext) return "File";
  return ext.toUpperCase();
}

/** Plural-aware count: "1 item" / "5 items". */
export function formatItemCount(n: number, label = "items"): string {
  return `${n} ${n === 1 ? label.replace(/s$/, "") : label}`;
}

