  useState,
  type CSSProperties,
  type DragEvent,
  type MouseEvent,
  type ReactNode,
  type RefObject,
} from "react";
import { ChevronDown, ChevronUp, ChevronsUpDown } from "lucide-react";
import { useVirtualizer } from "@tanstack/react-virtual";
import { cn } from "@/lib/utils";
import type {
  FileManagerItem,
  FileManagerItemRenderArgs,
  FileManagerLabels,
  FileManagerSortKey,
  FileManagerSortState,
