function HeaderCell({
  active,
  order,
  onClick,
  className,
  children,
}: {
  active: boolean;
  order: "asc" | "desc";
  onClick: () => void;
  className?: string;
  children: ReactNode;
}) {
  return (
    <button
      type="button"
      role="columnheader"
      aria-sort={
        active ? (order === "asc" ? "ascending" : "descending") : "none"
      }
      onClick={onClick}
      className={cn(
        "flex items-center gap-1 truncate text-left text-xs font-medium uppercase tracking-wide text-muted-foreground hover:text-foreground",
        className,
      )}
    >
      {children}
      {active ? (
        order === "asc" ? (
          <ChevronUp className="size-3" aria-hidden="true" />
        ) : (
          <ChevronDown className="size-3" aria-hidden="true" />
        )
      ) : (
        <ChevronsUpDown className="size-3 opacity-40" aria-hidden="true" />
      )}
    </button>
  );
}

export function FileManagerListView(props: FileManagerListViewProps) {
  const {
    items,
    rowHeight,
    sort,
    onSetSort,
    renamingId,
    validateRename,
    iconForNode,
    enableInternalDrag,
    dropTargetId,
    dropInvalid,
    renderItem,
    labels,
    scrollRef,
    virtualize,
    virtualizeThreshold,
    onItemClick,
    onItemDoubleClick,
    onItemContextMenu,
    onRenameCommit,
    onRenameCancel,
    onItemDragStart,
    onItemDragOver,
    onItemDragLeave,
    onItemDrop,
    onItemDragEnd,
  } = props;

  // Own the virtualizer locally — keeps virtualizer state inside this
  // component's scope so React Compiler doesn't strand stale measurements
  // across cross-component prop boundaries.
  const virtualizationActive =
    virtualize === "always" ||
    (virtualize === "auto" && items.length >= virtualizeThreshold);

  // Sync the scroll element ref into local state so `useVirtualizer` picks it
  // up on the second render (refs alone don't trigger re-render, which leaves
  // the virtualizer with a null scroll element and zero measured viewport).
  const [scrollEl, setScrollEl] = useState<HTMLDivElement | null>(
    () => scrollRef.current,
  );
  useEffect(() => {
    if (scrollRef.current && scrollRef.current !== scrollEl) {
      setScrollEl(scrollRef.current);
    }
  }, [scrollRef, scrollEl]);

  const virtualizer = useVirtualizer<HTMLDivElement, HTMLDivElement>({
    count: items.length,
    getScrollElement: () => scrollEl,
    estimateSize: () => rowHeight,
    overscan: 8,
    enabled: virtualizationActive,
  });

  const toggleSort = (key: FileManagerSortKey) => {
    if (sort.key === key) {
      onSetSort({ key, order: sort.order === "asc" ? "desc" : "asc" });
    } else {
      onSetSort({ key, order: "asc" });
    }
  };

  const headerRow = (
    <div
      role="row"
      className="sticky top-0 z-10 flex h-8 items-center gap-2 border-b border-border/60 bg-card/90 px-2 backdrop-blur-sm"
    >
      <span aria-hidden="true" className="size-4 shrink-0" />
      <HeaderCell
        active={sort.key === "name"}
        order={sort.order}
        onClick={() => toggleSort("name")}
        className="flex-1"
      >
        {labels.columnName}
      </HeaderCell>
      <HeaderCell
        active={sort.key === "modified"}
        order={sort.order}
        onClick={() => toggleSort("modified")}
        className="hidden w-32 shrink-0 sm:flex"
      >
        {labels.columnModified}
      </HeaderCell>
      <HeaderCell
        active={sort.key === "size"}
        order={sort.order}
        onClick={() => toggleSort("size")}
        className="hidden w-20 shrink-0 justify-end sm:flex"
      >
        {labels.columnSize}
      </HeaderCell>
      <HeaderCell
        active={sort.key === "type"}
        order={sort.order}
        onClick={() => toggleSort("type")}
        className="hidden w-16 shrink-0 md:flex"
      >
        {labels.columnType}
      </HeaderCell>
    </div>
  );

  const buildRow = (item: FileManagerItem, outerStyle?: CSSProperties) => {
    const isDropTarget = dropTargetId === item.node.id;
    const defaultItem = (
      <FileManagerItemView
        item={item}
        viewMode="list"
        iconSize="sm"
        isRenaming={renamingId === item.node.id}
        validateRename={validateRename}
        iconForNode={iconForNode}
        enableInternalDrag={enableInternalDrag}
        isDropTarget={isDropTarget}
        dropInvalid={isDropTarget && dropInvalid}
        onClick={onItemClick}
        onDoubleClick={onItemDoubleClick}
        onContextMenu={onItemContextMenu}
        onRenameCommit={onRenameCommit}
        onRenameCancel={onRenameCancel}
        onDragStart={onItemDragStart}
        onDragOver={onItemDragOver}
        onDragLeave={onItemDragLeave}
        onDrop={onItemDrop}
        onDragEnd={onItemDragEnd}
        outerStyle={
          outerStyle
            ? { ...outerStyle, height: `${rowHeight}px` }
            : { height: `${rowHeight}px` }
        }
      />
    );
    if (renderItem) {
      return (
        <div
          key={item.node.id}
          style={outerStyle}
          role="row"
        >
          {renderItem({ item, defaultItem, viewMode: "list" })}
        </div>
      );
    }
    return (
      <div
        key={item.node.id}
        role="row"
      >
        {defaultItem}
      </div>
    );
  };

  if (virtualizationActive) {
    const totalHeight = virtualizer.getTotalSize();
    const virtualItems = virtualizer.getVirtualItems();
    return (
      <div role="grid" aria-multiselectable="true">
        {headerRow}
        <div style={{ height: `${totalHeight}px`, position: "relative" }}>
          {virtualItems.map((vi) => {
            const item = items[vi.index];
            if (!item) return null;
            const outerStyle: CSSProperties = {
              position: "absolute",
              top: 0,
              left: 0,
              width: "100%",
              transform: `translateY(${vi.start}px)`,
            };
            return buildRow(item, outerStyle);
          })}
        </div>
      </div>
    );
  }

  return (
    <div role="grid" aria-multiselectable="true">
      {headerRow}
      <div className="flex flex-col">
        {items.map((item) => buildRow(item))}
      </div>
    </div>
  );
}

"use client";

import type {
  CSSProperties,
  DragEvent,
  MouseEvent,
  ReactNode,
} from "react";
import { cn } from "@/lib/utils";
import type {
  FileManagerIconSize,
  FileManagerItem,
  FileManagerValidateRenameArgs,
  FileManagerViewMode,
  FsNode,
} from "../types";
import { defaultFileIcon, defaultFolderIcon } from "../lib/icons";
import { formatBytes, formatDate, formatKind } from "../lib/format";
import { getNodeExtension } from "../lib/icons";
import { FileManagerRenameInput } from "./file-manager-rename-input";

const ICON_SIZE_PX: Record<FileManagerIconSize, number> = {
  sm: 32,
  md: 48,
  lg: 72,
};

const GRID_TRACK_PX: Record<FileManagerIconSize, number> = {
  sm: 80,
  md: 120,
  lg: 180,
};

interface FileManagerItemViewProps {
  item: FileManagerItem;
  viewMode: FileManagerViewMode;
  iconSize: FileManagerIconSize;
  isRenaming: boolean;
  validateRename?: (args: FileManagerValidateRenameArgs) => string | null;
  iconForNode?: (args: { node: FsNode }) => ReactNode;
  enableInternalDrag: boolean;
  /** Drop hover indicator state (only set on the hovered drop target). */
  isDropTarget?: boolean;
  dropInvalid?: boolean;
  // shared callbacks
  onClick: (e: MouseEvent, item: FileManagerItem) => void;
  onDoubleClick: (e: MouseEvent, item: FileManagerItem) => void;
  onContextMenu: (e: MouseEvent, item: FileManagerItem) => void;
  onRenameCommit: (id: string, nextName: string) => void;
  onRenameCancel: () => void;
  onDragStart?: (e: DragEvent, item: FileManagerItem) => void;
  onDragOver?: (e: DragEvent, item: FileManagerItem) => void;
  onDragLeave?: (e: DragEvent, item: FileManagerItem) => void;
  onDrop?: (e: DragEvent, item: FileManagerItem) => void;
  onDragEnd?: (e: DragEvent, item: FileManagerItem) => void;
  /** Used by virtualized list mode to position rows absolutely. */
  outerStyle?: CSSProperties;
}

export function FileManagerItemView(props: FileManagerItemViewProps) {
  const {
    item,
    viewMode,
    iconSize,
    isRenaming,
    validateRename,
    iconForNode,
    enableInternalDrag,
    isDropTarget,
    dropInvalid,
    onClick,
    onDoubleClick,
    onContextMenu,
    onRenameCommit,
    onRenameCancel,
    onDragStart,
    onDragOver,
    onDragLeave,
    onDrop,
    onDragEnd,
    outerStyle,
  } = props;

  const { node, selected, focused, cut } = item;
  const isFolder = node.type === "folder";
  const ext = getNodeExtension(node);

  const baseIcon = node.icon
    ? node.icon
    : iconForNode
      ? iconForNode({ node })
      : isFolder
        ? defaultFolderIcon(false, "size-full")
        : defaultFileIcon(node, "size-full");

  const sharedProps = {
    "data-item-id": node.id,
    role: "gridcell" as const,
    tabIndex: focused ? 0 : -1,
    "aria-selected": selected,
    draggable: enableInternalDrag && !isRenaming,
    onClick: (e: MouseEvent) => onClick(e, item),
    onDoubleClick: (e: MouseEvent) => onDoubleClick(e, item),
    onContextMenu: (e: MouseEvent) => onContextMenu(e, item),
    onDragStart: (e: DragEvent) =>
      enableInternalDrag && onDragStart && onDragStart(e, item),
    onDragOver: (e: DragEvent) => onDragOver?.(e, item),
    onDragLeave: (e: DragEvent) => onDragLeave?.(e, item),
    onDrop: (e: DragEvent) => onDrop?.(e, item),
    onDragEnd: (e: DragEvent) => onDragEnd?.(e, item),
  };

  if (viewMode === "grid") {
    const trackPx = GRID_TRACK_PX[iconSize];
    const iconPx = ICON_SIZE_PX[iconSize];
    return (
      <div
        {...sharedProps}
        style={outerStyle}
        className={cn(
          "group relative flex cursor-pointer select-none flex-col items-center gap-1.5 rounded-md p-2 outline-none transition-colors",
          selected
            ? "bg-secondary text-secondary-foreground"
            : "hover:bg-muted/60",
          focused &&
            "focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-inset",
          isDropTarget &&
            !dropInvalid &&
            "ring-2 ring-primary",
          isDropTarget && dropInvalid && "ring-2 ring-destructive",
          cut && "opacity-50",
        )}
      >
        <div
          aria-hidden="true"
          className={cn(
            "flex items-center justify-center opacity-80 transition-opacity",
            (selected || focused) && "opacity-100",
            "group-hover:opacity-100",
            isFolder
              ? "text-amber-600 dark:text-amber-400"
              : "text-muted-foreground",
            selected && "text-secondary-foreground",
          )}
          style={{ width: iconPx, height: iconPx }}
        >
          {baseIcon}
        </div>
        {isRenaming ? (
          <div style={{ width: trackPx - 8 }}>
            <FileManagerRenameInput
              node={node}
              validateRename={validateRename}
              onCommit={(next) => onRenameCommit(node.id, next)}
              onCancel={onRenameCancel}
            />
          </div>
        ) : (
          <span
            className="line-clamp-2 max-w-full text-center text-xs"
            title={node.name}
            style={{ maxWidth: trackPx - 4 }}
          >
            {node.name}
          </span>
        )}
      </div>
    );
  }

  // List mode
  return (
    <div
      {...sharedProps}
      style={outerStyle}
      className={cn(
        "group flex cursor-pointer select-none items-center gap-2 rounded-sm px-2 text-sm outline-none transition-colors",
        selected
          ? "bg-secondary text-secondary-foreground"
          : "hover:bg-muted/60",
        focused &&
          "focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-inset",
        isDropTarget &&
          !dropInvalid &&
          "ring-2 ring-primary",
        isDropTarget && dropInvalid && "ring-2 ring-destructive",
        cut && "opacity-50",
      )}
    >
      <span
        aria-hidden="true"
        className={cn(
          "flex shrink-0 items-center justify-center opacity-80 transition-opacity group-hover:opacity-100",
          (selected || focused) && "opacity-100",
          isFolder
            ? "text-amber-600 dark:text-amber-400"
            : "text-muted-foreground",
          selected && "text-secondary-foreground",
        )}
      >
        {baseIcon}
      </span>
      <span className="min-w-0 flex-1 truncate" title={node.name}>
        {isRenaming ? (
          <FileManagerRenameInput
            node={node}
            validateRename={validateRename}
            onCommit={(next) => onRenameCommit(node.id, next)}
            onCancel={onRenameCancel}
          />
        ) : (
          node.name
        )}
      </span>
      <span className="hidden w-32 shrink-0 text-xs text-muted-foreground sm:block">
        {formatDate(node.modifiedAt)}
      </span>
      <span className="hidden w-20 shrink-0 text-right font-mono text-xs text-muted-foreground sm:block">
        {isFolder ? "—" : formatBytes(node.size ?? 0)}
      </span>
      <span className="hidden w-16 shrink-0 text-xs text-muted-foreground md:block">
        {formatKind(ext, node.type)}
      </span>
    </div>
  );
}

"use client";

import { useEffect, useRef, useState } from "react";
import { cn } from "@/lib/utils";
import type { FsNode, FileManagerValidateRenameArgs } from "../types";

interface FileManagerRenameInputProps {
  node: FsNode;
  onCommit: (nextName: string) => void;
  onCancel: () => void;
  validateRename?: (args: FileManagerValidateRenameArgs) => string | null;
  className?: string;
}

export function FileManagerRenameInput(props: FileManagerRenameInputProps) {
  const { node, onCommit, onCancel, validateRename, className } = props;
  const [value, setValue] = useState(node.name);
  const [error, setError] = useState<string | null>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const input = inputRef.current;
    if (!input) return;
    input.focus();
    if (node.type === "folder") {
      input.select();
    } else {
      const dot = node.name.lastIndexOf(".");
      if (dot > 0) input.setSelectionRange(0, dot);
      else input.select();
    }
  }, [node.type, node.name]);

  const tryCommit = () => {
    const trimmed = value.trim();
    if (trimmed === "") {
      setError("Name cannot be empty");
      return;
    }
    if (trimmed === node.name) {
      onCancel();
      return;
    }
    if (validateRename) {
      const message = validateRename({ node, nextName: trimmed });
      if (message) {
        setError(message);
        return;
      }
    }
    onCommit(trimmed);
  };

  return (
    <div className={cn("relative flex flex-1 min-w-0 items-center", className)}>
      <input
        ref={inputRef}
        type="text"
        value={value}
        onChange={(e) => {
          setValue(e.target.value);
          if (error) setError(null);
        }}
        onKeyDown={(e) => {
          if (e.key === "Enter") {
            e.preventDefault();
            e.stopPropagation();
            tryCommit();
          } else if (e.key === "Escape") {
            e.preventDefault();
            e.stopPropagation();
            onCancel();
          } else {
            e.stopPropagation();
          }
        }}
        onBlur={() => tryCommit()}
        onClick={(e) => e.stopPropagation()}
        onDoubleClick={(e) => e.stopPropagation()}
        onPointerDown={(e) => e.stopPropagation()}
        aria-label={`Rename ${node.name}`}
        aria-invalid={error ? true : undefined}
        className={cn(
          "h-6 min-w-0 flex-1 rounded-sm border bg-background px-1 text-sm outline-none",
          "focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-1 focus-visible:ring-offset-background",
          error
            ? "border-destructive ring-1 ring-destructive"
            : "border-border",
        )}
      />
      {error ? (
        <span
          role="alert"
          className="pointer-events-none absolute left-0 top-full z-20 mt-0.5 rounded-sm bg-destructive px-1.5 py-0.5 text-xs text-destructive-foreground shadow-sm"
        >
          {error}
        </span>
      ) : null}
    </div>
  );
}

"use client";

import { useMemo, useState, type MouseEvent, type ReactNode } from "react";
import {
  ClipboardCopy,
  ClipboardPaste,
  FilePlus,
  FolderPlus,
  Pencil,
  RefreshCw,
  Scissors,
  Trash2,
} from "lucide-react";
import {
  ContextMenu,
  ContextMenuContent,
  ContextMenuItem,
  ContextMenuSeparator,
  ContextMenuTrigger,
} from "@/components/ui/context-menu";
import type {
  FileManagerActions,
  FileManagerContextMenuContext,
  FileManagerContextMenuItem,
  FileManagerLabels,
  FileManagerState,
  FsNode,
} from "../types";

interface FileManagerContextMenuProps {
  state: FileManagerState;
  actions: FileManagerActions;
  enabled: boolean;
  labels: FileManagerLabels;
  gates: {
    open: boolean;
    newFile: boolean;
    newFolder: boolean;
    cut: boolean;
    copy: boolean;
    paste: boolean;
    rename: boolean;
    delete: boolean;
    refresh: boolean;
  };
  wired: {
    onOpen: boolean;
    onCreate: boolean;
    onRename: boolean;
    onDelete: boolean;
    onMove: boolean;
    onPaste: boolean;
    onRefresh: boolean;
  };
  nodeIndex: ReadonlyMap<string, FsNode>;
  renderContextMenu?: (ctx: FileManagerContextMenuContext) => ReactNode;
  children: ReactNode;
}

export function FileManagerContextMenu(props: FileManagerContextMenuProps) {
  const {
    state,
    actions,
    enabled,
    labels,
    gates,
    wired,
    nodeIndex,
    renderContextMenu,
    children,
  } = props;
  const [target, setTarget] = useState<{
    node: FsNode | null;
    position: { x: number; y: number };
  } | null>(null);

  const captureTarget = (e: MouseEvent) => {
    const el = e.target as HTMLElement | null;
    const itemEl = el?.closest("[data-item-id]") as HTMLElement | null;
    const id = itemEl?.getAttribute("data-item-id") ?? null;
    const node = id ? (nodeIndex.get(id) ?? null) : null;
    setTarget({ node, position: { x: e.clientX, y: e.clientY } });
  };

  const defaultActions = useMemo<FileManagerContextMenuItem[]>(() => {
    if (!target) return [];
    const node = target.node;
    const list: FileManagerContextMenuItem[] = [];
    const hasClipboard = state.clipboard.kind !== null;
    const ids =
      node && state.selectedIds.has(node.id)
        ? Array.from(state.selectedIds)
        : node
          ? [node.id]
          : [];

    if (gates.open && wired.onOpen && node && node.type === "file") {
      list.push({
        id: "open",
        label: labels.contextOpen,
        icon: <FilePlus className="size-3.5" />,
        onSelect: () => actions.triggerOpen(node.id),
      });
    }
    if (gates.newFile && wired.onCreate) {
      list.push({
        id: "new-file",
        label: labels.contextNewFile,
        icon: <FilePlus className="size-3.5" />,
        onSelect: () => actions.triggerCreate("file"),
      });
    }
    if (gates.newFolder && wired.onCreate) {
      list.push({
        id: "new-folder",
        label: labels.contextNewFolder,
        icon: <FolderPlus className="size-3.5" />,
        onSelect: () => actions.triggerCreate("folder"),
      });
    }
    if (gates.cut && node && ids.length > 0) {
      list.push({
        id: "cut",
        label: labels.contextCut,
        icon: <Scissors className="size-3.5" />,
        onSelect: () => actions.cut(ids),
      });
    }
    if (gates.copy && node && ids.length > 0) {
      list.push({
        id: "copy",
        label: labels.contextCopy,
        icon: <ClipboardCopy className="size-3.5" />,
        onSelect: () => actions.copy(ids),
      });
    }
    if (gates.paste && wired.onPaste) {
      list.push({
        id: "paste",
        label: labels.contextPaste,
        icon: <ClipboardPaste className="size-3.5" />,
        disabled: !hasClipboard,
        onSelect: () => actions.paste(),
      });
    }
    if (gates.rename && wired.onRename && node) {
      list.push({
        id: "rename",
        label: labels.contextRename,
        icon: <Pencil className="size-3.5" />,
        onSelect: () => actions.startRename(node.id),
      });
    }
    if (gates.refresh && wired.onRefresh) {
      list.push({
        id: "refresh",
        label: labels.contextRefresh,
        icon: <RefreshCw className="size-3.5" />,
        onSelect: () => actions.refresh(state.currentFolderId),
      });
    }
    if (gates.delete && wired.onDelete && node && ids.length > 0) {
      list.push({
        id: "delete",
        label: labels.contextDelete,
        icon: <Trash2 className="size-3.5" />,
        destructive: true,
        onSelect: () => actions.triggerDelete(ids),
      });
    }
    return list;
  }, [target, state, gates, wired, labels, actions]);

  if (!enabled) {
    return <>{children}</>;
  }

  const ctx: FileManagerContextMenuContext = {
    state,
    actions,
    node: target?.node ?? null,
    defaultActions,
    position: target?.position ?? { x: 0, y: 0 },
    labels,
  };

  return (
    <ContextMenu>
      <ContextMenuTrigger asChild onContextMenu={captureTarget}>
        <div className="contents" onContextMenu={captureTarget}>
          {children}
        </div>
      </ContextMenuTrigger>
      <ContextMenuContent className="min-w-[180px]">
        {renderContextMenu ? (
          renderContextMenu(ctx)
        ) : defaultActions.length === 0 ? (
          <ContextMenuItem disabled>{labels.emptyTitle}</ContextMenuItem>
        ) : (
          <DefaultItems items={defaultActions} />
        )}
      </ContextMenuContent>
    </ContextMenu>
  );
}

function DefaultItems({ items }: { items: FileManagerContextMenuItem[] }) {
  const out: ReactNode[] = [];
  let lastSep = false;
  items.forEach((item, i) => {
    if (item.destructive && i > 0 && !lastSep) {
      out.push(<ContextMenuSeparator key={`sep-${i}`} />);
      lastSep = true;
    } else {
      lastSep = false;
    }
    out.push(
      <ContextMenuItem
        key={item.id}
        disabled={item.disabled}
        variant={item.destructive ? "destructive" : "default"}
        onSelect={() => item.onSelect()}
      >
        {item.icon}
        {item.label}
      </ContextMenuItem>,
    );
  });
  return <>{out}</>;
}

