import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import type { FsNode, FileManagerLabels } from "../types";

interface FileManagerDeleteConfirmProps {
  open: boolean;
  ids: string[];
  nodes: FsNode[];
  labels: FileManagerLabels;
  onConfirm: () => void;
  onCancel: () => void;
}

export function FileManagerDeleteConfirm(
  props: FileManagerDeleteConfirmProps,
) {
  const { open, ids, nodes, labels, onConfirm, onCancel } = props;
  const count = ids.length;
  const first = nodes[0]?.name ?? "";
  const title =
    count === 1
      ? `Delete "${first}"?`
      : labels.deleteConfirmTitle.replace("items", `${count} items`);
  const description =
    count === 1
      ? labels.deleteConfirmDescription
      : `Delete "${first}" and ${count - 1} other${count - 1 > 1 ? "s" : ""}? ${labels.deleteConfirmDescription}`;

  return (
    <AlertDialog
      open={open}
      onOpenChange={(next) => {
        if (!next) onCancel();
      }}
    >
      <AlertDialogContent>
        <AlertDialogHeader>
          <AlertDialogTitle>{title}</AlertDialogTitle>
          <AlertDialogDescription>{description}</AlertDialogDescription>
        </AlertDialogHeader>
        <AlertDialogFooter>
          <AlertDialogCancel onClick={onCancel}>
            {labels.deleteConfirmCancel}
          </AlertDialogCancel>
          <AlertDialogAction
            onClick={onConfirm}
            className="bg-destructive text-destructive-foreground hover:bg-destructive/90 focus-visible:ring-destructive/40"
          >
            {labels.deleteConfirmAction}
          </AlertDialogAction>
        </AlertDialogFooter>
      </AlertDialogContent>
    </AlertDialog>
  );
}

"use client";

import type { MarqueeRect } from "../hooks/use-marquee";

interface FileManagerMarqueeProps {
  rect: MarqueeRect | null;
}

/**
 * Visual rectangle drawn during marquee selection. Positioned absolutely
 * relative to the scroll container; consumer must place it inside a
 * `position: relative` ancestor (the content pane handles this).
 */
export function FileManagerMarquee(props: FileManagerMarqueeProps) {
  const { rect } = props;
  if (!rect) return null;
  return (
    <div
      aria-hidden="true"
      className="pointer-events-none absolute z-10 rounded-sm border border-primary bg-primary/15"
      style={{
        left: rect.left,
        top: rect.top,
        width: rect.width,
        height: rect.height,
      }}
    />
  );
}
